def min_cut_palindrome(s: str) -> int:
    n = len(s)
    pal = [[False]*n for _ in range(n)]
    for i in range(n-1, -1, -1):
        for j in range(i, n):
            if s[i] == s[j] and (j - i < 2 or pal[i+1][j-1]):
                pal[i][j] = True
    dp = [10**9] * (n + 1)
    dp[0] = -1
    for i in range(1, n + 1):
        for j in range(i):
            if pal[j][i-1] and dp[j] + 1 < dp[i]:
                dp[i] = dp[j] + 1
    return dp[n]

